import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(__dirname, "..", ".next-standalone", "server.js");
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});

import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(
        __dirname,
        "..",
        ".next-standalone",
        "server.js",
      );
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});

// ============================================
// INVITATION PAGE - MAIN STYLES
// ============================================

:host {
  --bg-image: none;
  --overlay-opacity: 0.26;
  --accent-color: #d6c3a5;
  --text-color: #f5efe6;
  --card-bg: rgba(255, 252, 246, 0.82);
  --card-border: rgba(255, 246, 232, 0.9);
  --card-text: #4b4150;
  --viewport-height: 100vh;
  --controls-height: 48px;
}

@supports (height: 100dvh) {
  :host {
    --viewport-height: 100dvh;
  }
}

.invitation-page {
  position: relative;
  width: 100%;
  height: var(--viewport-height);
  background-color: #0a0a0a;
  color: var(--text-color);
  font-family: 'Varela Round', 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  line-height: 1.6;
  overflow: hidden;
}

// ============================================
// PAGE CONTENT CONTAINER
// ============================================

.page-content {
  position: relative;
  width: 100%;
  height: var(--viewport-height);
  overflow: hidden;

  &::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, var(--overlay-opacity));
    z-index: 1;
    pointer-events: none;
  }
}

.page-background {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-image: var(--bg-image);
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  z-index: 0;
}

.slides-shell {
  position: relative;
  z-index: 2;
  width: 100%;
  height: var(--viewport-height);
  overflow: hidden;
  overscroll-behavior: none;
  -webkit-user-select: none;
  user-select: none;
  touch-action: none;
}

.slides-track {
  display: flex;
  width: 100%;
  height: calc(var(--viewport-height) - var(--controls-height) - env(safe-area-inset-bottom, 0px));
  transition: transform 420ms ease;
  will-change: transform;
}

.slide-page {
  flex: 0 0 100%;
  width: 100%;
  height: 100%;
  display: flex;
  justify-content: center;
}

.slide-scroll {
  width: min(680px, 100%);
  height: 100%;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 0.75rem;
  box-sizing: border-box;
}

.slide-card {
  width: 100%;
  max-width: 640px;
  max-height: 100%;
  overflow: hidden;
  border-radius: 20px;
  color: var(--card-text);
  background: linear-gradient(
    168deg,
    rgba(255, 254, 250, 0.94) 0%,
    var(--card-bg) 56%,
    rgba(247, 238, 226, 0.8) 100%
  );
  border: 1px solid var(--card-border);
  backdrop-filter: blur(7px) saturate(1.08);
  -webkit-backdrop-filter: blur(7px) saturate(1.08);
  box-shadow:
    0 16px 44px rgba(38, 27, 32, 0.24),
    inset 0 1px 0 rgba(255, 255, 255, 0.88);
}

.intro-card {
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 0.75rem 0;
}

// Transparent floating dots bar at the bottom
.slide-controls {
  height: calc(var(--controls-height) + env(safe-area-inset-bottom, 0px));
  display: flex;
  align-items: center;
  justify-content: center;
  padding-bottom: env(safe-area-inset-bottom, 0px);
  background: transparent;
}

.slide-dots {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: rgba(255, 249, 240, 0.35);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border-radius: 999px;
  border: 1px solid rgba(255, 255, 255, 0.42);
  box-shadow: 0 6px 18px rgba(30, 21, 25, 0.2);
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 999px;
  border: 0;
  padding: 0;
  background: rgba(86, 68, 78, 0.36);
  cursor: pointer;
  transition: transform 200ms ease, background-color 200ms ease, width 200ms ease;
  flex-shrink: 0;
}

.dot.active {
  background: var(--accent-color);
  width: 22px;
}

.swipe-hint {
  padding: 0.75rem 0 0.5rem;
  font-size: 0.78rem;
  color: #f6eee1;
  opacity: 0.84;
  letter-spacing: 0.06em;
  text-align: center;
  text-transform: uppercase;
  flex-shrink: 0;
}

// ============================================
// INTRO SLIDE LAYOUT
// ============================================

.intro-slide {
  width: 100%;
  min-height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 2rem 1.5rem 1rem;
  text-align: center;
  box-sizing: border-box;
  gap: 0;
}

// ============================================
// ANIMATIONS
// ============================================

@keyframes fadeInDown {
  from { opacity: 0; transform: translateY(-30px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(30px); }
  to   { opacity: 1; transform: translateY(0); }
}

@keyframes fadeIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}

@keyframes slideUp {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}

// ============================================
// RESPONSIVE DESIGN
// ============================================

@media (max-width: 1024px) {
}

@media (max-width: 768px) {
  .intro-slide {
    padding: 1.5rem 1rem 0.75rem;
  }

  .slide-card {
    border-radius: 16px;
  }
}

@media (max-width: 480px) {
  .intro-slide {
    padding: 1.25rem 0.75rem 0.5rem;
    justify-content: center;
  }


  .dot {
    width: 6px;
    height: 6px;
  }

  .dot.active {
    width: 18px;
  }

  .slide-scroll {
    padding: 0.5rem;
  }

  .slide-card {
    border-radius: 14px;
  }
}

// ============================================
// ACCESSIBILITY & PRINT
// ============================================

@media print {
  .page-background { display: none; }
}

@media (prefers-contrast: more) {
  .invitation-page { color: #fff; }
}

@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }
}

@media (prefers-color-scheme: dark) {
  .invitation-page {
    background-color: #0a0a0a;
    color: #ffffff;
  }
}

