import { Component, Input, Output, EventEmitter, OnInit, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, ReactiveFormsModule, Validators } from '@angular/forms';

@Component({
  selector: 'app-rsvp-section',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule],
  template: `
    <section class="rsvp-section">
      <div class="section-header">
        <h2 class="section-title">RSVP</h2>
        <p class="deadline">{{ deadlineText }}</p>
      </div>

      <form [formGroup]="form" (ngSubmit)="onSubmit()" class="rsvp-form">
        <div class="form-group">
          <label class="form-label">Guest Names</label>
          <p class="guest-names">{{ invitee?.guestNames.join(' & ') }}</p>
        </div>

        <div class="form-group">
          <label class="form-label">Will you attend?</label>
          <div class="button-group">
            <button
              type="button"
              class="choice-button"
              [class.active]="form.get('attending')?.value === true"
              (click)="setAttending(true)"
              [disabled]="submittingState()"
            >
              Yes, I'll be there ✓
            </button>
            <button
              type="button"
              class="choice-button"
              [class.active]="form.get('attending')?.value === false"
              (click)="setAttending(false)"
              [disabled]="submittingState()"
            >
              Sorry, can't make it
            </button>
          </div>
        </div>

        @if (form.get('attending')?.value === true) {
          <div class="form-group">
            <label class="form-label">Number of attendees</label>
            <select formControlName="attendeeCount" class="form-select">
              @for (n of attendeeOptions(); track n) {
                <option [value]="n">{{ n }} {{ n === 1 ? 'person' : 'people' }}</option>
              }
            </select>
          </div>
        }

        <div class="form-group">
          <label class="form-label">Message (optional)</label>
          <textarea
            formControlName="message"
            class="form-textarea"
            [attr.maxlength]="maxMessageLength"
            placeholder="Share your wishes or any special notes..."
          ></textarea>
          <p class="char-count">
            {{ (form.get('message')?.value?.length ?? 0) }} / {{ maxMessageLength }}
          </p>
        </div>

        <button
          type="submit"
          class="submit-button"
          [disabled]="!form.valid || submittingState()"
        >
          @if (submittingState()) {
            Submitting...
          } @else {
            Submit RSVP
          }
        </button>

        @if (errorState()) {
          <p class="error-message">{{ errorState() }}</p>
        }
      </form>
    </section>
  `,
  styles: [`
    .rsvp-section {
      padding: 1.75rem 1.25rem;
    }

    .section-header {
      text-align: center;
      margin-bottom: 2rem;
    }

    .section-title {
      font-size: 1.1rem;
      font-weight: 400;
      letter-spacing: 0.1em;
      margin: 0 0 0.5rem 0;
      font-family: 'Limelight', sans-serif;
      text-transform: uppercase;
    }

    .deadline {
      font-size: 0.9rem;
      opacity: 0.8;
      margin: 0;
      letter-spacing: 0.03em;
    }

    .rsvp-form {
      max-width: 500px;
      margin: 0 auto;
      display: flex;
      flex-direction: column;
      gap: 1.5rem;
    }

    .form-group {
      display: flex;
      flex-direction: column;
      gap: 0.8rem;
    }

    .form-label {
      font-size: 0.95rem;
      font-weight: 500;
      letter-spacing: 0.05em;
      text-transform: uppercase;
    }

    .guest-names {
      font-size: 1rem;
      opacity: 0.9;
      margin: 0;
      padding: 0.8rem;
      background: rgba(255, 255, 255, 0.05);
      border: 1px solid rgba(255, 255, 255, 0.1);
      border-radius: 6px;
    }

    .button-group {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1rem;
    }

    .choice-button {
      padding: 1rem 1.5rem;
      border: 2px solid rgba(255, 255, 255, 0.2);
      background: rgba(255, 255, 255, 0.05);
      color: inherit;
      cursor: pointer;
      border-radius: 6px;
      font-size: 0.9rem;
      font-weight: 500;
      letter-spacing: 0.03em;
      transition: all 0.3s ease;
      backdrop-filter: blur(10px);
    }

    .choice-button:hover:not(:disabled) {
      background: rgba(255, 255, 255, 0.1);
      border-color: rgba(255, 255, 255, 0.4);
    }

    .choice-button.active {
      background: var(--accent-color, #d6c3a5);
      border-color: var(--accent-color, #d6c3a5);
      color: #000;
    }

    .choice-button:disabled {
      opacity: 0.6;
      cursor: not-allowed;
    }

    .form-select,
    .form-textarea {
      padding: 0.8rem 1rem;
      border: 1px solid rgba(255, 255, 255, 0.2);
      background: rgba(255, 255, 255, 0.05);
      color: inherit;
      border-radius: 6px;
      font-size: 0.95rem;
      font-family: inherit;
      transition: all 0.3s ease;
      backdrop-filter: blur(10px);
    }

    .form-select:focus,
    .form-textarea:focus {
      outline: none;
      border-color: var(--accent-color, #d6c3a5);
      background: rgba(255, 255, 255, 0.08);
    }

    .form-select {
      cursor: pointer;
    }

    .form-select option {
      background: #1a1a1a;
      color: #fff;
    }

    .form-textarea {
      resize: vertical;
      min-height: 100px;
      max-height: 150px;
    }

    .char-count {
      font-size: 0.8rem;
      opacity: 0.6;
      margin: 0;
      text-align: right;
    }

    .submit-button {
      padding: 1rem 2rem;
      background: var(--accent-color, #d6c3a5);
      color: #000;
      border: none;
      border-radius: 6px;
      font-size: 0.95rem;
      font-weight: 600;
      letter-spacing: 0.05em;
      cursor: pointer;
      transition: all 0.3s ease;
      margin-top: 0.5rem;
    }

    .submit-button:hover:not(:disabled) {
      transform: translateY(-2px);
